// Copies the built @dynamic-forms-sdk/client IIFE bundle into src/sdkBundle.ts as a
// string constant. React Native/Metro can't load a node_modules file as raw text at
// runtime the way a web bundler can, so the WebView's HTML embeds the script inline
// instead of pointing at a <script src="..."> URL.
//
// Run after rebuilding sdk/client: `npm run sync-sdk` (see package.json).
const fs = require("fs");
const path = require("path");

const bundlePath = path.resolve(__dirname, "../../sdk/client/dist/index.global.js");
const outPath = path.resolve(__dirname, "../src/sdkBundle.ts");

if (!fs.existsSync(bundlePath)) {
  console.error(
    `Could not find ${bundlePath}. Build the client SDK first: cd sdk/client && npm run build`
  );
  process.exit(1);
}

const code = fs.readFileSync(bundlePath, "utf8");

const output = `// AUTO-GENERATED by scripts/syncSdkBundle.js — do not edit by hand.
// Source: sdk/client/dist/index.global.js. Re-run "npm run sync-sdk" after rebuilding it.
export const DFSDK_BUNDLE = ${JSON.stringify(code)};
`;

fs.writeFileSync(outPath, output);
console.log(`Wrote ${outPath} (${code.length} bytes embedded)`);
